const spec = {
  title: 'Recurring Tasks Feature Spec',
  author: 'Jane Smith',
  version: '0.3',
  sections: {
    problem_statement: 'Users need to schedule tasks that repeat on a regular basis. Currently, they must manually duplicate tasks every week or month, which is time-consuming and error-prone.',
    user_stories: [
      'As a project manager, I want to create recurring weekly tasks so that standups and check-ins are scheduled automatically.',
      'As a team member, I want recurring tasks to appear in my task list on the correct due date without manual intervention.'
    ],
    success_metrics: [
      'Recurring task feature adoption rate > 30% of active users within 60 days',
      'Reduction in manually duplicated tasks by 40% (measured via duplicate detection heuristic)',
      'NPS score for task management sub-experience increases by 5 points'
    ],
    scope_in: [
      'Weekly recurrence (every N weeks, specific day of week)',
      'Monthly recurrence (on a specific date or day of month)',
      'Option to set an end date or max occurrence count'
    ],
    scope_out: [
      'Custom recurrence rules (e.g., every 3rd Tuesday)',
      'Subtask recurrence',
      'Recurrence for projects (only tasks in scope)'
    ],
    open_questions: [
      'What happens to a recurring task if the original is deleted?',
      'How should subtasks of a recurring parent task be handled?'
    ],
    technical_considerations: 'Backend will need a scheduled job to create task instances. Estimated at 3 engineering weeks. Database schema change required.',
    launch_plan: 'Beta with 5 volunteer customers in week 8. GA in week 10 with in-app tooltip announcement.'
  }
};
return [{ json: { spec } }];

const { spec } = $input.first().json;
const specText = JSON.stringify(spec.sections, null, 2);
const system = `You are a senior PM reviewer. You evaluate product specs against a structured PM quality checklist. You give honest, specific feedback. You highlight what is strong and what is missing or unclear. Return ONLY valid JSON.`;
const user = `Review this product spec and provide structured feedback:

Title: ${spec.title}
Author: ${spec.author}
Version: ${spec.version}

${specText}

Return JSON:
{
  "overall_quality": "strong|adequate|needs-work|incomplete",
  "checklist": [
    { "item": "string — checklist item name", "status": "pass|partial|fail", "comment": "string — specific, actionable feedback" }
  ],
  "strengths": ["string"],
  "critical_gaps": ["string — must be resolved before engineering picks this up"],
  "suggested_improvements": ["string — nice to have before finalising"],
  "ready_for_engineering": true,
  "reviewer_summary": "string — 2-3 sentence overall assessment"
}`;
return [{ json: { spec, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Review Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.checklist || !Array.isArray(parsed.checklist)) return [{ json: { _error: true, reason: 'Missing checklist' } }];
return [{ json: { _error: false, review: parsed, meta: { spec_title: upstream.spec.title, author: upstream.spec.author, version: upstream.spec.version, generated_at: new Date().toISOString() } } }];
